    const { sessions, total } = await this.sessionsService.searchSessions(
      {
        ...validated,
        page: 0,
        pageSize: 10000000,
      },
      {
        teamId: targetTeamId,
        ...(cannotAccessTeammatesData ? { userId: requesterUid } : {}),
      },
      false,
      true,
    );

    return await CsvTranslator.createCsvFromSessions(sessions, validated.unit);
  }

