[{"name_path": "SessionsService/updateSession", "kind": "Method", "body_location": {"start_line": 324, "end_line": 398}, "body": "@CodedMethod('USS')
  async updateSession(
    teamId: string,
    sessionId: string,
    data: SessionUpdateDtoValidated,
    constraints: {
      userId?: string;
    },
  ): Promise<{ session: Session }> {
    const cbuilder = this.getCodeBuilder();
    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const player = data.playerId
        ? await t.findOne(Player, {
            where: {
              id: data.playerId,
              teamId,
              ...(constraints.userId
                ? { user: { id: constraints.userId } }
                : {}),
              deleteFlag: false,
            },
          })
        : null;

      if (data.playerId && !player) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_PLAYER_ID(cbuilder.build()),
        );
      }

      await this.checkConsistency(
        t,
        cbuilder,
        teamId,
        sessionId,
        constraints,
        false,
      );

      await t.update(
        Session,
        {
          id: sessionId,
        },
        {
          ...data,
          playerId: player?.id,
        },
      );

      // Retrieve saved-structured data safely
      const session =
        _.first(
          await this.sessionsPersistence.getSessions(
            t,
            [sessionId],
            {},
            constraints,
          ),
        ) ?? null;

      return {
        session,
      };
    });

    const session = tranResult.session!;

    await this.playersPersistence.supplySignedUrlToPlayers([session.player]);

    return {
      session: tranResult.session!,
    };
  }", "relative_path": "servers/api/src/app/services/sessions.service.ts"}]

